<?php
// Generated by Cursor prompt — Notification: Expense Request — date: 2026-03-15

namespace App\Notifications;

use Illuminate\Bus\Queueable;
use Illuminate\Contracts\Queue\ShouldQueue;
use Illuminate\Notifications\Notification;

class ExpenseRequestNotification extends Notification implements ShouldQueue
{
    use Queueable;

    public function __construct(
        public readonly int    $expenseId,
        public readonly string $personelName,
        public readonly float  $amount,
        public readonly string $currency,
        public readonly string $categoryName,
        public readonly string $expenseDate
    ) {}

    public function via(object $notifiable): array
    {
        return ['database', 'broadcast'];
    }

    public function toArray(object $notifiable): array
    {
        return [
            'type'         => 'expense_request',
            'icon'         => '🧾',
            'title'        => 'Yeni Masraf Talebi',
            'message'      => "{$this->personelName} — {$this->categoryName}",
            'subtitle'     => number_format($this->amount, 2) . " {$this->currency} · {$this->expenseDate}",
            'action_url'   => "/admin/expenses",
            'action_label' => 'Masrafı İncele',
            'model_id'     => $this->expenseId,
            'model_type'   => 'expense_request',
            'color'        => 'red',
        ];
    }

    public function toBroadcast(object $notifiable): array
    {
        return $this->toArray($notifiable);
    }
}
